import software.amazon.awssdk.auth.credentials.DefaultCredentialsProvider
import software.amazon.awssdk.regions.Region
import software.amazon.awssdk.services.s3.S3Client
import software.amazon.awssdk.services.s3.model.{PutObjectRequest, PutObjectResponse}
import software.amazon.awssdk.services.s3.model.S3Exception
import scala.util.{Try, Success, Failure}

class AWSService {
  private val credentialsProvider = DefaultCredentialsProvider.create()
  private val s3Client = S3Client.builder()
    .region(Region.US_EAST_1)
    .credentialsProvider(credentialsProvider)
    .build()

  def uploadFile(bucketName: String, key: String, content: String): Try[PutObjectResponse] = {
    Try {
      val putObjectRequest = PutObjectRequest.builder()
        .bucket(bucketName)
        .key(key)
        .build()
      
      s3Client.putObject(putObjectRequest, content)
    } match {
      case Success(response) => Success(response)
      case Failure(exception: S3Exception) => Failure(new Exception(s"Failed to upload file: ${exception.getMessage}"))
      case Failure(exception) => Failure(exception)
    }
  }

  def close(): Unit = {
    s3Client.close()
  }
}